import React, { useEffect, useMemo, useState } from "react";
import api from "../../api/axios";
import { useAuth } from "../../context/AuthContext";
import toast from "react-hot-toast";
import "../admin/Admin.css";
import "./Teacher.css";
import "./Classes.css";

const PAGE_SIZE = 10;

const STATUS_BADGE = {
  pending: "badge-yellow",
  active: "badge-green",
  completed: "badge-gray",
  cancelled: "badge-red",
};

const STATUS_LABEL = {
  pending: "Chờ khai giảng",
  active: "Đang học",
  completed: "Kết thúc",
  cancelled: "Đã hủy",
};

export default function TeacherClasses() {
  const { user } = useAuth();

  // State nguồn dữ liệu cần để ghép bảng lớp với khóa học và học viên.
  const [classes, setClasses] = useState([]);
  const [courses, setCourses] = useState([]);
  const [allUsers, setAllUsers] = useState([]);
  const [enrollments, setEnrollments] = useState([]);
  const [loading, setLoading] = useState(true);

  // State điều khiển UI tìm kiếm, phân trang và panel chi tiết.
  const [selected, setSelected] = useState(null);
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);

  useEffect(() => {
    if (!user) {
      return;
    }

    const fetchAll = async () => {
      setLoading(true);

      try {
        const [classResponse, courseResponse, userResponse] = await Promise.all([
          api.get("/admin/classes"),
          api.get("/courses"),
          api.get("/users"),
        ]);

        const allClasses = classResponse.data.data || [];
        const allCourses = courseResponse.data.data || [];
        const usersResponse = userResponse.data.data || [];

        const teacherId = Number(user.id);
        const myClasses = allClasses.filter((classroom) => Number(classroom.teacherId) === teacherId);

        setCourses(allCourses);
        setClasses(myClasses);
        setAllUsers(usersResponse);

        const enrollmentResponses = await Promise.all(
          myClasses.map((classroom) =>
            api.get(`/enrollments/class/${classroom.id}`)
              .then((response) => (response.data.data || []).map((enrollment) => ({ ...enrollment, classId: classroom.id })))
              .catch(() => [])
          )
        );

        setEnrollments(enrollmentResponses.flat());
      } catch (error) {
        console.error(error);
        toast.error("Không thể tải dữ liệu lớp học");
      } finally {
        setLoading(false);
      }
    };

    fetchAll();
  }, [user]);

  const getCourse = (id) => courses.find((course) => Number(course.id) === Number(id));
  const getUser = (id) => allUsers.find((account) => Number(account.id) === Number(id));

  const getApprovedEnrollments = (classId) => (
    enrollments.filter((enrollment) =>
      Number(enrollment.classId) === Number(classId)
      && ["approved", "enrolled", "completed"].includes(enrollment.status))
  );

  // Bảng lớp đã qua tìm kiếm theo tên lớp hoặc tên khóa học.
  const filteredClasses = useMemo(() => (
    classes.filter((classroom) => {
      const course = getCourse(classroom.courseId);

      return !search
        || classroom.name?.toLowerCase().includes(search.toLowerCase())
        || course?.title?.toLowerCase().includes(search.toLowerCase());
    })
  ), [classes, courses, search]);

  const totalPages = Math.max(1, Math.ceil(filteredClasses.length / PAGE_SIZE));
  const paginatedClasses = filteredClasses.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);
  const selectedStudents = selected ? getApprovedEnrollments(selected.id) : [];

  return (
    <div className="admin-page fade-in teacher-classes">
      <section className="teacher-classes__hero">
        <div>
          <p className="teacher-classes__eyebrow">Class workspace</p>
          <h1>Lớp của tôi</h1>
          <p className="teacher-classes__subtitle">
            Theo dõi sĩ số, khóa học gắn với từng lớp và mở nhanh danh sách học viên ngay trong cùng màn hình.
          </p>
        </div>
        <div className="teacher-classes__hero-card">
          <span>Tổng lớp phụ trách</span>
          <strong>{classes.length}</strong>
          <p>{filteredClasses.length} lớp đang hiển thị theo bộ lọc hiện tại.</p>
        </div>
      </section>

      <div className="toolbar">
        <input
          className="search-input"
          placeholder="🔍 Tìm lớp hoặc khóa học"
          value={search}
          onChange={(event) => {
            setSearch(event.target.value);
            setPage(1);
          }}
        />
        <span className="teacher-classes__counter">{filteredClasses.length} lớp</span>
      </div>

      {/* Layout 2 cột: bảng lớp bên trái, panel học viên bên phải khi có lớp được chọn. */}
      <div className={`teacher-classes__layout ${selected ? "teacher-classes__layout--split" : ""}`}>
        <div className="table-wrapper">
          {loading ? (
            <div className="page-loading"><div className="spinner" /></div>
          ) : (
            <>
              <table className="data-table">
                <thead>
                  <tr>
                    <th>Tên lớp</th>
                    <th>Khóa học</th>
                    <th>Sĩ số</th>
                    <th>Thời gian</th>
                    <th>Trạng thái</th>
                    <th>Thao tác</th>
                  </tr>
                </thead>
                <tbody>
                  {paginatedClasses.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="empty-state"><p>Chưa có lớp nào được phân công cho bạn</p></td>
                    </tr>
                  ) : (
                    paginatedClasses.map((classroom) => {
                      const course = getCourse(classroom.courseId);
                      const approvedStudents = getApprovedEnrollments(classroom.id);

                      return (
                        <tr
                          key={classroom.id}
                          className={selected?.id === classroom.id ? "teacher-classes__row--active" : ""}
                        >
                          <td className="teacher-classes__name">{classroom.name}</td>
                          <td>
                            {course ? (
                              <div className="teacher-classes__course">
                                <span className={`badge ${course.examType === "IELTS" ? "badge-blue" : course.examType === "TOEIC" ? "badge-green" : "badge-gray"}`}>
                                  {course.examType}
                                </span>
                                <span className="teacher-classes__course-title">{course.title}</span>
                              </div>
                            ) : (
                              <span className="teacher-classes__muted">—</span>
                            )}
                          </td>
                          <td>
                            <span className="teacher-classes__name">{approvedStudents.length}</span>
                            <span className="teacher-classes__capacity">/{classroom.maxStudents}</span>
                          </td>
                          <td className="teacher-classes__muted teacher-classes__tiny">
                            {classroom.startDate ? new Date(classroom.startDate).toLocaleDateString("vi-VN") : "—"}
                            {" → "}
                            {classroom.endDate ? new Date(classroom.endDate).toLocaleDateString("vi-VN") : "—"}
                          </td>
                          <td>
                            <span className={`badge ${STATUS_BADGE[classroom.status] || "badge-gray"}`}>
                              {STATUS_LABEL[classroom.status] || classroom.status}
                            </span>
                          </td>
                          <td>
                            <button
                              className="btn btn-primary btn-sm"
                              onClick={() => setSelected(selected?.id === classroom.id ? null : classroom)}
                            >
                              {selected?.id === classroom.id ? "Đóng" : "Xem HV"}
                            </button>
                          </td>
                        </tr>
                      );
                    })
                  )}
                </tbody>
              </table>

              {filteredClasses.length > PAGE_SIZE && (
                <div className="pagination">
                  <span className="pagination-info">
                    {((page - 1) * PAGE_SIZE) + 1}–{Math.min(page * PAGE_SIZE, filteredClasses.length)} / {filteredClasses.length}
                  </span>
                  <div className="pagination-btns">
                    <button className="page-btn" disabled={page === 1} onClick={() => setPage((current) => current - 1)}>‹</button>
                    {Array.from({ length: totalPages }, (_, index) => (
                      <button
                        key={index + 1}
                        className={`page-btn ${page === index + 1 ? "active" : ""}`}
                        onClick={() => setPage(index + 1)}
                      >
                        {index + 1}
                      </button>
                    ))}
                    <button className="page-btn" disabled={page === totalPages} onClick={() => setPage((current) => current + 1)}>›</button>
                  </div>
                </div>
              )}
            </>
          )}
        </div>

        {selected && (
          <aside className="section-card teacher-classes__detail-card">
            <div className="teacher-classes__detail-head">
              <div>
                <h3 className="section-title teacher-classes__detail-title">{selected.name}</h3>
                <p className="teacher-classes__tiny teacher-classes__muted">
                  {selectedStudents.length} học viên đã duyệt
                </p>
              </div>
              <button className="btn btn-ghost btn-sm" onClick={() => setSelected(null)}>✕</button>
            </div>

            <table className="data-table">
              <thead>
                <tr>
                  <th>Học viên</th>
                  <th>Tiến độ</th>
                  <th>TT</th>
                </tr>
              </thead>
              <tbody>
                {selectedStudents.length === 0 ? (
                  <tr>
                    <td colSpan={3} className="empty-state"><p>Chưa có học viên</p></td>
                  </tr>
                ) : (
                  selectedStudents.map((enrollment) => {
                    const account = getUser(enrollment.userId);

                    return (
                      <tr key={enrollment.id}>
                        <td>
                          <div className="teacher-classes__student">
                            <div className="avatar teacher-classes__student-avatar">
                              {(account?.name || "?").charAt(0).toUpperCase()}
                            </div>
                            <div>
                              <p className="teacher-classes__student-name">{account?.name || `ID: ${enrollment.userId}`}</p>
                              <p className="teacher-classes__tiny teacher-classes__muted">{account?.email || ""}</p>
                            </div>
                          </div>
                        </td>
                        <td>
                          <div className="teacher-classes__progress">
                            <progress max="100" value={enrollment.progress || 0} />
                            <span>{enrollment.progress || 0}%</span>
                          </div>
                        </td>
                        <td>
                          <span className={`badge ${enrollment.status === "enrolled" ? "badge-green" : enrollment.status === "approved" ? "badge-blue" : "badge-gray"}`}>
                            {enrollment.status}
                          </span>
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </aside>
        )}
      </div>
    </div>
  );
}
